<section class="page-head"><h1>Ofertas</h1><p>Aplicá descuentos por porcentaje sin cambiar la estructura de Supabase. Se guardan en archivo local y se reflejan en catálogo.</p></section><form class="panel filter-admin" method="get"><input name="q" placeholder="Buscar producto por nombre" value="<?= e($_GET['q']??'') ?>"><button class="btn primary">Buscar</button><a class="btn outline" href="<?= site_url('admin/ofertas') ?>">Limpiar</a></form><div class="offer-grid"><?php foreach(array_slice($productos,0,80) as $p): $o=$active[(string)$p['id']]??null; $base=(float)($p['precio']??$p['precio_venta']??0); ?><article class="offer-card"><img src="<?= e($p['portada'] ?: asset_url('img/logo.png')) ?>"><div class="body"><span class="badge-dark">#<?= e($p['id']) ?></span><h3><?= e($p['titulo']??'') ?></h3><strong><?= money_ar($base) ?></strong><?php if($o): ?><span class="badge-sale"><?= e($o['descuento']) ?>% OFF hasta <?= e($o['hasta']) ?></span><strong><?= money_ar($base*(1-($o['descuento']/100))) ?></strong><form method="post" action="<?= site_url('admin/ofertas/eliminar/'.$p['id']) ?>"><?= csrf_field() ?><button class="btn small">Quitar oferta</button></form><?php else: ?><form method="post" action="<?= site_url('admin/ofertas/guardar') ?>"><?= csrf_field() ?><input type="hidden" name="producto_id" value="<?= e($p['id']) ?>"><div class="edit-grid two"><label>% descuento<input name="descuento" type="number" min="1" max="95" value="10"></label><label>Días<input name="dias" type="number" min="1" max="60" value="2"></label></div><button class="btn small primary">Aplicar oferta</button></form><?php endif; ?></div></article><?php endforeach; ?></div>
